class TagEditor extends HTMLElement{constructor(){super();this.data=[];this.tagClass=this.getAttribute("tagClass")??"btn btn-primary m-1";this.inputClass=this.getAttribute("inputClass")??"form-control mt-3";this.containerClass=this.getAttribute("containerClass")??"col-md-6";this.backingControlId=this.getAttribute("for");this.backingControl=document.getElementById(this.backingControlId);this.container=document.createElement("div");this.container.className=this.containerClass;this.tagContainer=document.createElement("div");this.container.appendChild(this.tagContainer);this.inputContainer=document.createElement("div");this.inputBox=document.createElement("input");this.inputBox.type="text";this.inputBox.className=this.inputClass;this.inputContainer.appendChild(this.inputBox);this.container.appendChild(this.inputContainer);this.appendChild(this.container)}connectedCallback(){let n=JSON.parse(this.backingControl.value);for(let t=0;t<n.length;t++)this.addTag(n[t]);this.inputBox.addEventListener("keyup",n=>{n.preventDefault(),n.keyCode===13&&(this.addTag(this.inputBox.value),this.inputBox.value="")})}addTag(n){this.data.push(n);this.backingControl&&(this.backingControl.value=JSON.stringify(this.data));const t=document.createElement("span");t.innerHTML=n;t.className=this.tagClass;this.tagContainer.appendChild(t);t.addEventListener("click",n=>{this.data=this.data.filter(t=>t!==n.target.innerHTML),this.backingControl.value=JSON.stringify(this.data),this.tagContainer.removeChild(n.target)})}}window.customElements.define("tag-builder",TagBuilder);